import{_ as t,o as a,c as i,ae as s}from"./chunks/framework.MAq6t5g3.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"RehearsalLink","text":"「あの指示、どこだっけ？」をゼロに。","tagline":"音楽合奏の録音をAIが自動解析。演奏と会話を瞬時に仕分けし、リハーサルの振り返りをかつてないほどスムーズにする iOSアプリ。","actions":[{"theme":"brand","text":"使い方を見る","link":"/guide/"}]},"features":[{"title":"🪄 波形が色分けされる魔法","details":"AIが「演奏（青）」、「会話・指示（緑）」、「無音」を自動識別。タップするだけで聞きたい箇所へ一っ飛び。"},{"title":"🎙 言葉が見える","details":"指導内容をテキスト化。音を出せない電車内でも振り返りが可能に。"},{"title":"📤 欲しい音だけ抽出","details":"「演奏だけ」「会話だけ」を繋げて書き出し、メンバーへの共有が爆速に。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),l={name:"index.md"};function r(o,e,d,n,c,v){return a(),i("div",null,[...e[0]||(e[0]=[s('<div class="custom-container" style="text-align:center;margin:80px 0;"><h2 style="font-size:2rem;margin-bottom:20px;font-weight:700;">リハーサル録音に「目次」を。</h2><p style="color:var(--vp-c-text-2);max-width:600px;margin:0 auto 40px;">合奏練習を録音しても、数時間のデータから特定の指示箇所や演奏の失敗箇所を探すのは大変な作業です。RehearsalLinkは、あなたの貴重な時間を節約します。</p><div class="waveform-preview" style="max-width:700px;margin:0 auto;"><div class="waveform-bar blue" style="height:40%;"></div><div class="waveform-bar blue" style="height:60%;"></div><div class="waveform-bar blue" style="height:80%;"></div><div class="waveform-bar green" style="height:30%;"></div><div class="waveform-bar green" style="height:45%;"></div><div class="waveform-bar green" style="height:20%;"></div><div class="waveform-bar blue" style="height:70%;"></div><div class="waveform-bar blue" style="height:90%;"></div><div class="waveform-bar blue" style="height:75%;"></div><div class="waveform-bar purple" style="height:40%;"></div><div class="waveform-bar purple" style="height:60%;"></div><div class="waveform-bar purple" style="height:50%;"></div><div class="waveform-bar blue" style="height:85%;"></div><div class="waveform-bar blue" style="height:70%;"></div></div><p style="font-size:0.9rem;color:var(--vp-c-text-3);">AIが演奏（青）、会話（緑）、文字起こし済み（紫）を自動で識別</p></div><h2 id="😫-こんな悩み、ありませんか" tabindex="-1">😫 こんな悩み、ありませんか？ <a class="header-anchor" href="#😫-こんな悩み、ありませんか" aria-label="Permalink to &quot;😫 こんな悩み、ありませんか？&quot;">​</a></h2><ul><li>「2時間の合奏録音から、先生の細かい指示を探すのに苦労している」</li><li>「『通し練習の演奏だけ』を連続で聴きたい」</li><li>「録音係が毎回、曲名とタイムスタンプをメモする作業に疲れた」</li></ul><p><strong>RehearsalLinkが、その悩みをすべて解決します。</strong></p><h2 id="👥-活用事例" tabindex="-1">👥 活用事例 <a class="header-anchor" href="#👥-活用事例" aria-label="Permalink to &quot;👥 活用事例&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">🗣 指導者・指揮者</p><p>ご自身の指導の振り返りや、次回の練習計画の作成に最適です。AIによる文字起こしで、どのような指示を出したかを後から簡単に確認できます。</p></div><div class="tip custom-block"><p class="custom-block-title">🎺 パートリーダー</p><p>指摘された箇所の「会話＋直後の演奏」だけを抽出し、パート内に共有。効率的な復習をサポートします。</p></div><div class="tip custom-block"><p class="custom-block-title">📱 録音係</p><p>アプリに録音を入れるだけで自動的に「目次」が完成。練習後の録音共有作業が数分で完了します。</p></div><div style="text-align:center;margin:80px 0;"><h3>今すぐリハーサルをアップデートしよう</h3><a href="#" class="download-badge"><span style="font-size:0.8rem;display:block;line-height:1;">Download on the</span><span style="font-size:1.4rem;">App Store</span></a></div>',9)])])}const m=t(l,[["render",r]]);export{p as __pageData,m as default};
